int factorial(int num) {
    int result = 1;
    for (int i = 2; i <= num; i++) {
        result *= i;
    }
    return result;
}

int main(void) {
    int n, sum = 0;

    printf("Enter an integer n: ");
    scanf("%d", &n);

    if (n < 1 || n > 11) {
        printf("Invalid input. Please enter a number between 1 and 11.\n");
        return 1;
    }

    for (int i = 1; i <= n; i++) {
        sum += factorial(i) / (i + 1);
    }

    printf("sum = %.3f\n", (double)sum);

    return 0;
}

