int main(void) {
    int n;
    double sum = 0.0;

    // Read input from user
    printf("Enter an integer n (1 <= n <= 12): ");
    scanf("%d", &n);

    // Compute the square denominator series
    for (int i = 1; i <= n; i++) {
        double term = (3 * i - 1) / ((double)i * i + i + 1);
        sum += term;
    }

    // Print the final result with 3 decimal places
    printf("result = %.3f\n", sum);

    return 0;
}

